import React, { useState, useEffect } from 'react';
import { Link } from 'react-router-dom';
import axios from 'axios';

function Cart({ token }) {
  const [cart, setCart] = useState(null);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState('');

  useEffect(() => {
    fetchCart();
  }, []);

  const fetchCart = async () => {
    try {
      const res = await axios.get('/api/cart', {
        headers: { Authorization: `Bearer ${token}` }
      });
      setCart(res.data);
    } catch (err) {
      setError('Failed to load cart');
    } finally {
      setLoading(false);
    }
  };

  const handleRemoveItem = async (productId) => {
    try {
      await axios.post('/api/cart/remove', { productId }, {
        headers: { Authorization: `Bearer ${token}` }
      });
      fetchCart();
    } catch (err) {
      setError('Failed to remove item');
    }
  };

  const handleUpdateQuantity = async (productId, quantity) => {
    try {
      await axios.post('/api/cart/update', { productId, quantity }, {
        headers: { Authorization: `Bearer ${token}` }
      });
      fetchCart();
    } catch (err) {
      setError('Failed to update quantity');
    }
  };

  if (loading) return <div className="loading">Loading cart...</div>;

  const total = cart?.items.reduce((sum, item) => sum + (item.productId?.price || 0) * item.quantity, 0) || 0;

  return (
    <div>
      <h1>Shopping Cart</h1>
      {error && <div className="error-message">{error}</div>}

      {!cart || cart.items.length === 0 ? (
        <div style={{ textAlign: 'center', padding: '40px' }}>
          <p>Your cart is empty</p>
          <Link to="/"><button>Continue Shopping</button></Link>
        </div>
      ) : (
        <>
          <table className="cart-table">
            <thead>
              <tr>
                <th>Product</th>
                <th>Price</th>
                <th>Size</th>
                <th>Color</th>
                <th>Quantity</th>
                <th>Total</th>
                <th>Action</th>
              </tr>
            </thead>
            <tbody>
              {cart.items.map(item => (
                <tr key={item.productId?._id}>
                  <td>{item.productId?.name}</td>
                  <td>฿{item.productId?.price}</td>
                  <td>{item.size || '-'}</td>
                  <td>{item.color || '-'}</td>
                  <td>
                    <input
                      type="number"
                      min="1"
                      max="10"
                      value={item.quantity}
                      onChange={(e) => handleUpdateQuantity(item.productId._id, parseInt(e.target.value))}
                      style={{ width: '60px' }}
                    />
                  </td>
                  <td>฿{(item.productId?.price || 0) * item.quantity}</td>
                  <td>
                    <button
                      onClick={() => handleRemoveItem(item.productId._id)}
                      style={{ background: '#ff6b6b' }}
                    >
                      Remove
                    </button>
                  </td>
                </tr>
              ))}
            </tbody>
          </table>

          <div className="checkout-summary">
            <div className="summary-item">
              <span>Subtotal:</span>
              <span>฿{total}</span>
            </div>
            <div className="summary-item">
              <span>Shipping:</span>
              <span>฿0</span>
            </div>
            <div className="summary-item total">
              <span>Total:</span>
              <span>฿{total}</span>
            </div>
          </div>

          <div style={{ textAlign: 'right', marginTop: '20px' }}>
            <Link to="/">
              <button style={{ marginRight: '10px' }}>Continue Shopping</button>
            </Link>
            <Link to="/checkout">
              <button>Proceed to Checkout</button>
            </Link>
          </div>
        </>
      )}
    </div>
  );
}

export default Cart;
